const e=JSON.parse(`[{"id":1,"section":"A","theme":"Daily activities","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une personne court dans le parc","image_prompt":"A person running in a green park, sunny day"},{"id":"B","text":"Une personne fait du vélo","image_prompt":"A person riding a bicycle on a city path"},{"id":"C","text":"Une personne nage","image_prompt":"A person swimming in a blue pool"},{"id":"D","text":"Une personne marche avec un chien","image_prompt":"A person walking a golden retriever in a park"}],"correct":0,"transcript_fr":"J'adore commencer ma journée par un petit footing au parc quand il fait beau.","transcript_en":"I love starting my day with a quick jog in the park when the weather is nice.","points":[{"point":1,"male_lines":["J'adore commencer ma journée par un petit footing au parc quand il fait beau."],"female_lines":[]}]},{"id":2,"section":"A","theme":"Food and drink","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Quelqu'un boit un café","image_prompt":"A person holding a steaming cup of coffee"},{"id":"B","text":"Quelqu'un mange une salade","image_prompt":"A fresh green salad in a bowl"},{"id":"C","text":"Quelqu'un cuisine un gâteau","image_prompt":"A person baking a cake in a kitchen"},{"id":"D","text":"Quelqu'un achète des légumes","image_prompt":"A person buying vegetables at a market"}],"correct":1,"transcript_fr":"Pour le dîner ce soir, je vais préparer une grande salade verte avec des tomates et du concombre.","transcript_en":"For dinner tonight, I'm going to prepare a big green salad with tomatoes and cucumber.","points":[{"point":1,"male_lines":["Pour le dîner ce soir, je vais préparer une grande salade verte avec des tomates et du concombre."],"female_lines":[]}]},{"id":3,"section":"A","theme":"Transportation","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un bus à l'arrêt","image_prompt":"A city bus at a bus stop"},{"id":"B","text":"Une voiture dans un embouteillage","image_prompt":"Cars stuck in traffic jam"},{"id":"C","text":"Un train en gare","image_prompt":"A train arriving at a station platform"},{"id":"D","text":"Un avion à l'aéroport","image_prompt":"An airplane at an airport gate"}],"correct":2,"transcript_fr":"Le train de 8 heures en direction de Montréal va bientôt partir, veuillez monter à bord.","transcript_en":"The 8 o'clock train to Montreal will be departing soon, please board now.","points":[{"point":1,"male_lines":["Le train de 8 heures en direction de Montréal va bientôt partir, veuillez monter à bord."],"female_lines":[]}]},{"id":4,"section":"A","theme":"Weather","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Il neige","image_prompt":"Heavy snowfall in a city street"},{"id":"B","text":"Il pleut","image_prompt":"Rain falling on an umbrella"},{"id":"C","text":"Il fait soleil","image_prompt":"Bright sunny day with clear blue sky"},{"id":"D","text":"Il y a du brouillard","image_prompt":"Thick fog covering a landscape"}],"correct":3,"transcript_fr":"Attention sur les routes, le brouillard est très dense ce matin dans la région de Québec.","transcript_en":"Caution on the roads, the fog is very dense this morning in the Quebec region.","points":[{"point":1,"male_lines":["Attention sur les routes, le brouillard est très dense ce matin dans la région de Québec."],"female_lines":[]}]},{"id":5,"section":"A","theme":"Shopping","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Quelqu'un essaie des chaussures","image_prompt":"A person trying on shoes in a store"},{"id":"B","text":"Quelqu'un paie à la caisse","image_prompt":"A person paying at a checkout counter"},{"id":"C","text":"Quelqu'un regarde des vêtements","image_prompt":"A person browsing clothes on a rack"},{"id":"D","text":"Quelqu'un demande un remboursement","image_prompt":"A person at customer service desk"}],"correct":0,"transcript_fr":"Je cherche des bottes pour l'hiver, est-ce que je peux essayer celles-ci en taille 42 ?","transcript_en":"I'm looking for winter boots, can I try these ones in size 42?","points":[{"point":1,"male_lines":["Je cherche des bottes pour l'hiver, est-ce que je peux essayer celles-ci en taille 42 ?"],"female_lines":[]}]},{"id":6,"section":"A","theme":"Work","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une réunion d'équipe","image_prompt":"People in a business meeting around a table"},{"id":"B","text":"Quelqu'un travaille sur ordinateur","image_prompt":"A person typing on a laptop computer"},{"id":"C","text":"Quelqu'un parle au téléphone","image_prompt":"A person talking on a phone at a desk"},{"id":"D","text":"Quelqu'un imprime des documents","image_prompt":"A person using a printer in an office"}],"correct":1,"transcript_fr":"Je dois finir ce rapport pour demain, je vais travailler sur mon ordinateur toute la soirée.","transcript_en":"I need to finish this report for tomorrow, I'm going to work on my computer all evening.","points":[{"point":1,"male_lines":["Je dois finir ce rapport pour demain, je vais travailler sur mon ordinateur toute la soirée."],"female_lines":[]}]},{"id":7,"section":"B","theme":"Everyday conversation","question":"Quel est le sujet principal de cette conversation ?","options":[{"id":"A","text":"Organiser une fête","image_prompt":""},{"id":"B","text":"Planifier un voyage","image_prompt":""},{"id":"C","text":"Choisir un restaurant","image_prompt":""},{"id":"D","text":"Acheter des billets","image_prompt":""}],"correct":2,"transcript_fr":"Marc: Salut Julie, tu as faim ? Je pensais qu'on pourrait aller manger quelque part. Julie: Bonne idée ! Tu as envie de quoi ? Marc: Je ne sais pas, peut-être de la cuisine italienne ? Julie: Parfait, il y a un nouveau restaurant qui vient d'ouvrir sur la rue Saint-Denis.","transcript_en":"Marc: Hi Julie, are you hungry? I thought we could go eat somewhere. Julie: Good idea! What are you in the mood for? Marc: I don't know, maybe Italian food? Julie: Perfect, there's a new restaurant that just opened on Saint-Denis street.","points":[{"point":1,"male_lines":["Salut Julie, tu as faim ? Je pensais qu'on pourrait aller manger quelque part.","Je ne sais pas, peut-être de la cuisine italienne ?"],"female_lines":["Bonne idée ! Tu as envie de quoi ?","Parfait, il y a un nouveau restaurant qui vient d'ouvrir sur la rue Saint-Denis."]}]},{"id":8,"section":"B","theme":"Everyday conversation","question":"Que décident les personnes de faire ?","options":[{"id":"A","text":"Aller au cinéma","image_prompt":""},{"id":"B","text":"Faire du shopping","image_prompt":""},{"id":"C","text":"Visiter un musée","image_prompt":""},{"id":"D","text":"Faire une promenade","image_prompt":""}],"correct":0,"transcript_fr":"Sophie: Tu as envie de faire quelque chose ce week-end ? Pierre: Oui, on pourrait aller voir ce nouveau film au cinéma du centre-ville. Sophie: Lequel ? Celui avec l'acteur français ? Pierre: Exactement ! Il passe demain soir à 19h. Sophie: Génial, je suis partante !","transcript_en":"Sophie: Do you want to do something this weekend? Pierre: Yes, we could go see that new movie at the downtown cinema. Sophie: Which one? The one with the French actor? Pierre: Exactly! It's playing tomorrow night at 7pm. Sophie: Great, I'm in!","points":[{"point":1,"male_lines":["Oui, on pourrait aller voir ce nouveau film au cinéma du centre-ville.","Exactement ! Il passe demain soir à 19h."],"female_lines":["Tu as envie de faire quelque chose ce week-end ?","Lequel ? Celui avec l'acteur français ?","Génial, je suis partante !"]}]},{"id":9,"section":"B","theme":"Everyday conversation","question":"Quel est le problème mentionné dans la conversation ?","options":[{"id":"A","text":"La voiture est en panne","image_prompt":""},{"id":"B","text":"Le train est en retard","image_prompt":""},{"id":"C","text":"L'appartement est froid","image_prompt":""},{"id":"D","text":"L'ordinateur ne marche pas","image_prompt":""}],"correct":1,"transcript_fr":"Luc: Tu es en retard, tout va bien ? Marie: Désolée, le train a eu un problème technique. Luc: Ah bon ? Depuis quand ? Marie: Il est resté bloqué en gare pendant vingt minutes. Luc: C'est pénible ces retards ! Marie: Oui, surtout quand on a un rendez-vous important.","transcript_en":"Luc: You're late, is everything okay? Marie: Sorry, the train had a technical problem. Luc: Oh really? Since when? Marie: It was stuck at the station for twenty minutes. Luc: These delays are annoying! Marie: Yes, especially when you have an important appointment.","points":[{"point":1,"male_lines":["Tu es en retard, tout va bien ?","Ah bon ? Depuis quand ?","C'est pénible ces retards !"],"female_lines":["Désolée, le train a eu un problème technique.","Il est resté bloqué en gare pendant vingt minutes.","Oui, surtout quand on a un rendez-vous important."]}]},{"id":10,"section":"B","theme":"Everyday conversation","question":"De quoi parlent les deux personnes ?","options":[{"id":"A","text":"D'un livre","image_prompt":""},{"id":"B","text":"D'un film","image_prompt":""},{"id":"C","text":"D'une exposition","image_prompt":""},{"id":"D","text":"D'un concert","image_prompt":""}],"correct":3,"transcript_fr":"Jean: Tu as entendu parler du concert de Céline Dion à Montréal ? Claire: Oui, mais les billets sont très chers. Jean: C'est vrai, mais c'est sa tournée d'adieu. Claire: Je sais, j'aimerais tellement y aller ! Jean: On pourrait économiser ensemble pour s'acheter des places ?","transcript_en":"Jean: Have you heard about Céline Dion's concert in Montreal? Claire: Yes, but the tickets are very expensive. Jean: That's true, but it's her farewell tour. Claire: I know, I would love to go! Jean: Could we save up together to buy tickets?","points":[{"point":1,"male_lines":["Tu as entendu parler du concert de Céline Dion à Montréal ?","C'est vrai, mais c'est sa tournée d'adieu.","On pourrait économiser ensemble pour s'acheter des places ?"],"female_lines":["Oui, mais les billets sont très chers.","Je sais, j'aimerais tellement y aller !"]}]},{"id":11,"section":"C","theme":"Public announcement","question":"Quelle est l'annonce principale ?","options":[{"id":"A","text":"Un changement d'horaire","image_prompt":""},{"id":"B","text":"Une fermeture temporaire","image_prompt":""},{"id":"C","text":"Une promotion spéciale","image_prompt":""},{"id":"D","text":"Un nouvel employé","image_prompt":""}],"correct":1,"transcript_fr":"Mesdames et messieurs, nous vous informons que la station de métro Berri-UQAM sera fermée ce week-end pour des travaux de rénovation. Les trains ne s'arrêteront pas à cette station du samedi 6h jusqu'au dimanche 23h. Nous vous recommandons d'utiliser les stations alternatives suivantes : Sherbrooke ou Champ-de-Mars. Des navettes de bus gratuites seront disponibles entre ces stations. Nous vous prions de nous excuser pour ce désagrément et vous remercions de votre compréhension. Pour plus d'informations, consultez notre site web ou notre application mobile. Bonne journée à tous.","transcript_en":"Ladies and gentlemen, we inform you that Berri-UQAM metro station will be closed this weekend for renovation work. Trains will not stop at this station from Saturday 6am until Sunday 11pm. We recommend using the following alternative stations: Sherbrooke or Champ-de-Mars. Free shuttle buses will be available between these stations. We apologize for this inconvenience and thank you for your understanding. For more information, please consult our website or mobile app. Have a good day everyone.","points":[{"point":1,"male_lines":["Mesdames et messieurs, nous vous informons que la station de métro Berri-UQAM sera fermée ce week-end pour des travaux de rénovation.","Les trains ne s'arrêteront pas à cette station du samedi 6h jusqu'au dimanche 23h.","Nous vous recommandons d'utiliser les stations alternatives suivantes : Sherbrooke ou Champ-de-Mars.","Des navettes de bus gratuites seront disponibles entre ces stations.","Nous vous prions de nous excuser pour ce désagrément et vous remercions de votre compréhension."],"female_lines":[]}]},{"id":12,"section":"C","theme":"Public announcement","question":"Quel est le message principal ?","options":[{"id":"A","text":"Une alerte météo","image_prompt":""},{"id":"B","text":"Un avis de recherche","image_prompt":""},{"id":"C","text":"Une annonce de sécurité","image_prompt":""},{"id":"D","text":"Une information sur les horaires","image_prompt":""}],"correct":0,"transcript_fr":"Attention, avis de tempête hivernale pour la région de Montréal et ses environs. Environnement Canada prévoit de fortes chutes de neige commençant ce soir et se poursuivant jusqu'à demain matin. On attend entre 20 et 30 centimètres de neige avec des vents forts. Les conditions de visibilité seront réduites et les routes seront glissantes. Évitez les déplacements non essentiels. Si vous devez sortir, équipez votre véhicule de pneus d'hiver et conduisez prudemment. Restez à l'écoute des médias pour les mises à jour. Prenez soin de vous et de vos proches.","transcript_en":"Attention, winter storm warning for the Montreal region and surrounding areas. Environment Canada predicts heavy snowfall starting this evening and continuing until tomorrow morning. We expect between 20 and 30 centimeters of snow with strong winds. Visibility will be reduced and roads will be slippery. Avoid non-essential travel. If you must go out, equip your vehicle with winter tires and drive carefully. Stay tuned to the media for updates. Take care of yourself and your loved ones.","points":[{"point":1,"male_lines":["Attention, avis de tempête hivernale pour la région de Montréal et ses environs.","Environnement Canada prévoit de fortes chutes de neige commençant ce soir et se poursuivant jusqu'à demain matin.","On attend entre 20 et 30 centimètres de neige avec des vents forts.","Les conditions de visibilité seront réduites et les routes seront glissantes.","Évitez les déplacements non essentiels."],"female_lines":[]}]},{"id":13,"section":"C","theme":"Public announcement","question":"Quel est l'objet de ce message ?","options":[{"id":"A","text":"Une invitation à un événement","image_prompt":""},{"id":"B","text":"Un rappel de rendez-vous","image_prompt":""},{"id":"C","text":"Une annulation de service","image_prompt":""},{"id":"D","text":"Un changement de politique","image_prompt":""}],"correct":2,"transcript_fr":"Bonjour à tous, c'est la bibliothèque municipale de Québec. Nous vous informons que suite à une panne de chauffage, notre établissement sera fermé aujourd'hui. Tous les ateliers et activités prévus sont annulés. Les livres devant être retournés aujourd'hui ne seront pas pénalisés. Vous pouvez prolonger vos prêts en ligne sur notre site internet. Nous espérons rouvrir demain matin à 9 heures. Suivez nos réseaux sociaux pour les dernières nouvelles. Merci de votre patience et à bientôt.","transcript_en":"Hello everyone, this is the Quebec City municipal library. We inform you that due to a heating breakdown, our establishment will be closed today. All scheduled workshops and activities are cancelled. Books due to be returned today will not be penalized. You can renew your loans online on our website. We hope to reopen tomorrow morning at 9am. Follow our social media for the latest news. Thank you for your patience and see you soon.","points":[{"point":1,"male_lines":["Bonjour à tous, c'est la bibliothèque municipale de Québec.","Nous vous informons que suite à une panne de chauffage, notre établissement sera fermé aujourd'hui.","Tous les ateliers et activités prévus sont annulés.","Les livres devant être retournés aujourd'hui ne seront pas pénalisés.","Vous pouvez prolonger vos prêts en ligne sur notre site internet."],"female_lines":[]}]},{"id":14,"section":"C","theme":"Public announcement","question":"Quelle information est donnée ?","options":[{"id":"A","text":"L'ouverture d'un nouveau magasin","image_prompt":""},{"id":"B","text":"Des soldes exceptionnels","image_prompt":""},{"id":"C","text":"Un concours avec des prix","image_prompt":""},{"id":"D","text":"Une prolongation d'horaire","image_prompt":""}],"correct":3,"transcript_fr":"Chers clients du Centre Commercial Laurier, nous avons le plaisir de vous annoncer que pendant la période des Fêtes, nos magasins prolongeront leurs heures d'ouverture. Du 15 décembre au 24 décembre, nous serons ouverts jusqu'à 21h du lundi au samedi, et le dimanche de 12h à 17h. Le 24 décembre, fermeture exceptionnelle à 17h. Profitez de ces heures supplémentaires pour faire vos achats de Noël dans le calme. Notre équipe reste à votre disposition pour vous aider. Joyeuses Fêtes à tous !","transcript_en":"Dear customers of Laurier Shopping Center, we are pleased to announce that during the Holiday season, our stores will extend their opening hours. From December 15th to 24th, we will be open until 9pm Monday through Saturday, and Sunday from 12pm to 5pm. On December 24th, special closing at 5pm. Take advantage of these extra hours to do your Christmas shopping in peace. Our team remains at your disposal to help you. Happy Holidays to all!","points":[{"point":1,"male_lines":["Chers clients du Centre Commercial Laurier, nous avons le plaisir de vous annoncer que pendant la période des Fêtes, nos magasins prolongeront leurs heures d'ouverture.","Du 15 décembre au 24 décembre, nous serons ouverts jusqu'à 21h du lundi au samedi, et le dimanche de 12h à 17h.","Le 24 décembre, fermeture exceptionnelle à 17h.","Profitez de ces heures supplémentaires pour faire vos achats de Noël dans le calme.","Notre équipe reste à votre disposition pour vous aider."],"female_lines":[]}]},{"id":15,"section":"C","theme":"Public announcement","question":"Quel est le but de ce message ?","options":[{"id":"A","text":"Présenter un nouveau produit","image_prompt":""},{"id":"B","text":"Recruter du personnel","image_prompt":""},{"id":"C","text":"Informer d'une réparation","image_prompt":""},{"id":"D","text":"Promouvoir un abonnement","image_prompt":""}],"correct":2,"transcript_fr":"Chers usagers de la piscine municipale, nous vous informons que le bassin olympique sera fermé pour maintenance du 1er au 7 mars prochain. Nos techniciens effectueront des travaux d'étanchéité et remplaceront les filtres. Le petit bassin restera ouvert avec des horaires modifiés : 10h à 16h uniquement. Les cours de natation sont suspendus pendant cette période mais seront remplacés par des séances en salle de gym gratuites. Les abonnements seront automatiquement prolongés d'une semaine. Merci de votre compréhension.","transcript_en":"Dear users of the municipal swimming pool, we inform you that the Olympic pool will be closed for maintenance from March 1st to 7th. Our technicians will carry out waterproofing work and replace the filters. The small pool will remain open with modified hours: 10am to 4pm only. Swimming lessons are suspended during this period but will be replaced by free gym sessions. Subscriptions will be automatically extended by one week. Thank you for your understanding.","points":[{"point":1,"male_lines":["Chers usagers de la piscine municipale, nous vous informons que le bassin olympique sera fermé pour maintenance du 1er au 7 mars prochain.","Nos techniciens effectueront des travaux d'étanchéité et remplaceront les filtres.","Le petit bassin restera ouvert avec des horaires modifiés : 10h à 16h uniquement.","Les cours de natation sont suspendus pendant cette période mais seront remplacés par des séances en salle de gym gratuites.","Les abonnements seront automatiquement prolongés d'une semaine."],"female_lines":[]}]},{"id":16,"section":"C","theme":"Public announcement","question":"Quelle est l'information principale ?","options":[{"id":"A","text":"Un déménagement","image_prompt":""},{"id":"B","text":"Une grève","image_prompt":""},{"id":"C","text":"Une rénovation","image_prompt":""},{"id":"D","text":"Une fusion","image_prompt":""}],"correct":0,"transcript_fr":"Nous souhaitons informer notre clientèle que notre restaurant déménage ! Après dix ans dans notre local actuel sur l'avenue du Parc, nous déménageons au 450 rue Saint-Jean dans le Vieux-Québec. Notre dernière journée ici sera le 30 avril et nous rouvrirons dans nos nouveaux locaux le 15 mai. Le nouveau restaurant sera plus grand, avec une terrasse et un parking. Nous gardons la même équipe et le même menu que vous aimez. Venez célébrer notre déménagement avec nous ! Réservez dès maintenant pour notre soirée d'ouverture.","transcript_en":"We wish to inform our customers that our restaurant is moving! After ten years in our current location on Park Avenue, we are moving to 450 Saint-Jean Street in Old Quebec. Our last day here will be April 30th and we will reopen in our new location on May 15th. The new restaurant will be bigger, with a terrace and parking. We keep the same team and the same menu that you love. Come celebrate our move with us! Book now for our opening night.","points":[{"point":1,"male_lines":["Nous souhaitons informer notre clientèle que notre restaurant déménage !","Après dix ans dans notre local actuel sur l'avenue du Parc, nous déménageons au 450 rue Saint-Jean dans le Vieux-Québec.","Notre dernière journée ici sera le 30 avril et nous rouvrirons dans nos nouveaux locaux le 15 mai.","Le nouveau restaurant sera plus grand, avec une terrasse et un parking.","Nous gardons la même équipe et le même menu que vous aimez."],"female_lines":[]}]},{"id":17,"section":"D","theme":"Short dialogue - Intention","question":"Quelle est l'intention du premier locuteur ?","options":[{"id":"A","text":"Demander un conseil","image_prompt":""},{"id":"B","text":"Faire une suggestion","image_prompt":""},{"id":"C","text":"Exprimer un doute","image_prompt":""},{"id":"D","text":"Demander une permission","image_prompt":""}],"correct":1,"transcript_fr":"Thomas: On devrait peut-être partir plus tôt demain pour éviter les embouteillages. Anne: Bonne idée, à quelle heure tu proposes ? Thomas: Vers 7 heures ça te va ? Anne: Parfait, je serai prête.","transcript_en":"Thomas: Maybe we should leave earlier tomorrow to avoid traffic jams. Anne: Good idea, what time do you suggest? Thomas: Around 7 o'clock, does that work for you? Anne: Perfect, I'll be ready.","points":[{"point":1,"male_lines":["On devrait peut-être partir plus tôt demain pour éviter les embouteillages.","Vers 7 heures ça te va ?"],"female_lines":["Bonne idée, à quelle heure tu proposes ?","Parfait, je serai prête."]}]},{"id":18,"section":"D","theme":"Short dialogue - Intention","question":"Que veut faire le premier locuteur ?","options":[{"id":"A","text":"Se plaindre","image_prompt":""},{"id":"B","text":"Refuser une invitation","image_prompt":""},{"id":"C","text":"Demander des informations","image_prompt":""},{"id":"D","text":"Proposer son aide","image_prompt":""}],"correct":3,"transcript_fr":"Paul: Tu as l'air débordée, je peux t'aider avec ces dossiers ? Sophie: Ce serait gentil, j'ai vraiment trop de travail. Paul: Pas de problème, je vais m'occuper de ceux-là. Sophie: Merci beaucoup Paul, tu me sauves la vie !","transcript_en":"Paul: You look overwhelmed, can I help you with these files? Sophie: That would be nice, I really have too much work. Paul: No problem, I'll take care of those. Sophie: Thank you very much Paul, you're a lifesaver!","points":[{"point":1,"male_lines":["Tu as l'air débordée, je peux t'aider avec ces dossiers ?","Pas de problème, je vais m'occuper de ceux-là."],"female_lines":["Ce serait gentil, j'ai vraiment trop de travail.","Merci beaucoup Paul, tu me sauves la vie !"]}]},{"id":19,"section":"D","theme":"Short dialogue - Intention","question":"Quelle est l'attitude de la deuxième personne ?","options":[{"id":"A","text":"Elle est enthousiaste","image_prompt":""},{"id":"B","text":"Elle est hésitante","image_prompt":""},{"id":"C","text":"Elle est indifférente","image_prompt":""},{"id":"D","text":"Elle est critique","image_prompt":""}],"correct":0,"transcript_fr":"Marc: J'ai réservé une table au nouveau restaurant japonais pour samedi ! Julie: Génial ! J'ai tellement envie d'essayer leur cuisine ! Marc: Apparemment leur sushi est excellent. Julie: Je suis sûre qu'on va passer une super soirée !","transcript_en":"Marc: I booked a table at the new Japanese restaurant for Saturday! Julie: Great! I've been wanting to try their cuisine so much! Marc: Apparently their sushi is excellent. Julie: I'm sure we'll have a great evening!","points":[{"point":1,"male_lines":["J'ai réservé une table au nouveau restaurant japonais pour samedi !","Apparemment leur sushi est excellent."],"female_lines":["Génial ! J'ai tellement envie d'essayer leur cuisine !","Je suis sûre qu'on va passer une super soirée !"]}]},{"id":20,"section":"D","theme":"Short dialogue - Intention","question":"Pourquoi le premier locuteur appelle-t-il ?","options":[{"id":"A","text":"Pour confirmer un rendez-vous","image_prompt":""},{"id":"B","text":"Pour annuler une réservation","image_prompt":""},{"id":"C","text":"Pour se plaindre d'un service","image_prompt":""},{"id":"D","text":"Pour demander un remboursement","image_prompt":""}],"correct":1,"transcript_fr":"Monsieur Lambert: Bonjour, je voudrais annuler ma réservation pour ce soir. Réceptionniste: Bien sûr monsieur, sous quel nom était-ce ? Monsieur Lambert: Au nom de Lambert, table pour quatre personnes. Réceptionniste: C'est noté, votre réservation est annulée. Monsieur Lambert: Merci beaucoup, bonne journée.","transcript_en":"Mr. Lambert: Hello, I would like to cancel my reservation for tonight. Receptionist: Of course sir, under what name was it? Mr. Lambert: Under the name Lambert, table for four people. Receptionist: Noted, your reservation is cancelled. Mr. Lambert: Thank you very much, have a good day.","points":[{"point":1,"male_lines":["Bonjour, je voudrais annuler ma réservation pour ce soir.","Au nom de Lambert, table pour quatre personnes.","Merci beaucoup, bonne journée."],"female_lines":["Bien sûr monsieur, sous quel nom était-ce ?","C'est noté, votre réservation est annulée."]}]},{"id":21,"section":"D","theme":"Short dialogue - Intention","question":"Quel est le but de cette conversation ?","options":[{"id":"A","text":"Organiser une réunion","image_prompt":""},{"id":"B","text":"Résoudre un problème","image_prompt":""},{"id":"C","text":"Prendre une décision","image_prompt":""},{"id":"D","text":"Partager une information","image_prompt":""}],"correct":2,"transcript_fr":"Lucie: On part en vacances à la montagne ou à la mer cet été ? Pierre: Je préfère la montagne, il fait trop chaud à la plage. Lucie: D'accord, mais j'aimerais quand même pouvoir me baigner un peu. Pierre: On peut trouver un lac en montagne ! Lucie: Bonne idée, réservons ça !","transcript_en":"Lucie: Are we going on vacation to the mountains or the sea this summer? Pierre: I prefer the mountains, it's too hot at the beach. Lucie: Okay, but I would still like to be able to swim a bit. Pierre: We can find a lake in the mountains! Lucie: Good idea, let's book that!","points":[{"point":1,"male_lines":["Je préfère la montagne, il fait trop chaud à la plage.","On peut trouver un lac en montagne !"],"female_lines":["On part en vacances à la montagne ou à la mer cet été ?","D'accord, mais j'aimerais quand même pouvoir me baigner un peu.","Bonne idée, réservons ça !"]}]},{"id":22,"section":"D","theme":"Short dialogue - Intention","question":"Que cherche à faire le premier locuteur ?","options":[{"id":"A","text":"Vendre quelque chose","image_prompt":""},{"id":"B","text":"Emprunter un objet","image_prompt":""},{"id":"C","text":"Demander un service","image_prompt":""},{"id":"D","text":"Donner un conseil","image_prompt":""}],"correct":2,"transcript_fr":"Jean: Excusez-moi, pourriez-vous m'indiquer où se trouve la station de métro la plus proche ? Passante: Oui bien sûr, continuez tout droit et tournez à gauche après le café. Jean: Merci beaucoup, c'est à quelle distance environ ? Passante: À peu près cinq minutes à pied. Jean: Parfait, merci encore !","transcript_en":"Jean: Excuse me, could you tell me where the nearest metro station is? Passerby: Yes of course, continue straight ahead and turn left after the café. Jean: Thank you very much, approximately how far is it? Passerby: About five minutes walk. Jean: Perfect, thanks again!","points":[{"point":1,"male_lines":["Excusez-moi, pourriez-vous m'indiquer où se trouve la station de métro la plus proche ?","Merci beaucoup, c'est à quelle distance environ ?","Parfait, merci encore !"],"female_lines":["Oui bien sûr, continuez tout droit et tournez à gauche après le café.","À peu près cinq minutes à pied."]}]},{"id":23,"section":"E","theme":"Radio interview","question":"Quel est le sujet principal de l'interview ?","options":[{"id":"A","text":"La création d'une entreprise","image_prompt":""},{"id":"B","text":"L'agriculture urbaine","image_prompt":""},{"id":"C","text":"La cuisine bio","image_prompt":""},{"id":"D","text":"Le recyclage","image_prompt":""}],"correct":1,"transcript_fr":"Journaliste: Bonjour Madame Tremblay, vous êtes fondatrice d'un projet d'agriculture urbaine à Montréal. Pouvez-vous nous en parler ? Mme Tremblay: Bonjour, oui nous avons transformé des toits d'immeubles en jardins potagers. Journaliste: Quels légumes cultivez-vous ? Mme Tremblay: Principalement des tomates, des herbes aromatiques et des laitues. Journaliste: Comment les résidents réagissent-ils ? Mme Tremblay: Ils sont très enthousiastes, certains viennent même nous aider à cultiver !","transcript_en":"Journalist: Hello Mrs. Tremblay, you are the founder of an urban agriculture project in Montreal. Can you tell us about it? Mrs. Tremblay: Hello, yes we have transformed building rooftops into vegetable gardens. Journalist: What vegetables do you grow? Mrs. Tremblay: Mainly tomatoes, aromatic herbs, and lettuce. Journalist: How do the residents react? Mrs. Tremblay: They are very enthusiastic, some even come to help us cultivate!","points":[{"point":1,"male_lines":["Bonjour Madame Tremblay, vous êtes fondatrice d'un projet d'agriculture urbaine à Montréal. Pouvez-vous nous en parler ?","Quels légumes cultivez-vous ?","Comment les résidents réagissent-ils ?"],"female_lines":["Bonjour, oui nous avons transformé des toits d'immeubles en jardins potagers.","Principalement des tomates, des herbes aromatiques et des laitues.","Ils sont très enthousiastes, certains viennent même nous aider à cultiver !"]}]},{"id":24,"section":"E","theme":"Radio interview","question":"Quel problème est discuté dans cette interview ?","options":[{"id":"A","text":"Le manque de logements","image_prompt":""},{"id":"B","text":"La pollution de l'air","image_prompt":""},{"id":"C","text":"Le trafic routier","image_prompt":""},{"id":"D","text":"Le bruit dans la ville","image_prompt":""}],"correct":2,"transcript_fr":"Journaliste: Monsieur Dubois, vous êtes expert en urbanisme. Que pensez-vous du trafic à Québec ? M. Dubois: C'est critique aux heures de pointe, surtout sur les ponts. Journaliste: Quelles solutions proposez-vous ? M. Dubois: Développer les transports en commun et les pistes cyclables. Journaliste: Ces mesures sont-elles appliquées ? M. Dubois: Progressivement, mais il faut plus de volonté politique.","transcript_en":"Journalist: Mr. Dubois, you are an urban planning expert. What do you think of traffic in Quebec City? Mr. Dubois: It's critical at rush hour, especially on the bridges. Journalist: What solutions do you propose? Mr. Dubois: Develop public transportation and bike lanes. Journalist: Are these measures being implemented? Mr. Dubois: Gradually, but more political will is needed.","points":[{"point":1,"male_lines":["Monsieur Dubois, vous êtes expert en urbanisme. Que pensez-vous du trafic à Québec ?","Quelles solutions proposez-vous ?","Ces mesures sont-elles appliquées ?"],"female_lines":["C'est critique aux heures de pointe, surtout sur les ponts.","Développer les transports en commun et les pistes cyclables.","Progressivement, mais il faut plus de volonté politique."]}]},{"id":25,"section":"E","theme":"Radio interview","question":"De quoi parle cette interview ?","options":[{"id":"A","text":"D'un festival de musique","image_prompt":""},{"id":"B","text":"D'une exposition d'art","image_prompt":""},{"id":"C","text":"D'un spectacle de danse","image_prompt":""},{"id":"D","text":"D'un film québécois","image_prompt":""}],"correct":0,"transcript_fr":"Journaliste: Nous avons avec nous le directeur du Festival de Jazz de Montréal. Bonjour Monsieur Lavoie. M. Lavoie: Bonjour, merci de nous recevoir. Journaliste: Quels artistes seront présents cette année ? M. Lavoie: Nous avons programmé plus de cinquante groupes, dont plusieurs internationaux. Journaliste: Les billets sont-ils déjà en vente ? M. Lavoie: Oui, depuis la semaine dernière, et ils partent très vite !","transcript_en":"Journalist: We have with us the director of the Montreal Jazz Festival. Hello Mr. Lavoie. Mr. Lavoie: Hello, thank you for having us. Journalist: Which artists will be present this year? Mr. Lavoie: We have programmed more than fifty groups, including several international ones. Journalist: Are tickets already on sale? Mr. Lavoie: Yes, since last week, and they're selling very fast!","points":[{"point":1,"male_lines":["Nous avons avec nous le directeur du Festival de Jazz de Montréal. Bonjour Monsieur Lavoie.","Quels artistes seront présents cette année ?","Les billets sont-ils déjà en vente ?"],"female_lines":["Bonjour, merci de nous recevoir.","Nous avons programmé plus de cinquante groupes, dont plusieurs internationaux.","Oui, depuis la semaine dernière, et ils partent très vite !"]}]},{"id":26,"section":"E","theme":"Radio interview","question":"Quel est le thème de cette interview ?","options":[{"id":"A","text":"La santé mentale","image_prompt":""},{"id":"B","text":"L'alimentation équilibrée","image_prompt":""},{"id":"C","text":"L'exercice physique","image_prompt":""},{"id":"D","text":"Le sommeil","image_prompt":""}],"correct":1,"transcript_fr":"Journaliste: Docteur Martin, vous êtes nutritionniste. Quels conseils donnez-vous pour bien manger ? Dr Martin: Manger varié, cinq fruits et légumes par jour, et limiter les sucres. Journaliste: Beaucoup de gens trouvent cela difficile. Dr Martin: Il suffit de petits changements quotidiens, comme remplacer les boissons sucrées par de l'eau. Journaliste: Et les régimes restrictifs ? Dr Martin: À éviter, ils ne fonctionnent pas sur le long terme.","transcript_en":"Journalist: Dr. Martin, you are a nutritionist. What advice do you give for eating well? Dr. Martin: Eat varied, five fruits and vegetables per day, and limit sugars. Journalist: Many people find this difficult. Dr. Martin: Just small daily changes, like replacing sugary drinks with water. Journalist: And restrictive diets? Dr. Martin: To be avoided, they don't work in the long term.","points":[{"point":1,"male_lines":["Docteur Martin, vous êtes nutritionniste. Quels conseils donnez-vous pour bien manger ?","Beaucoup de gens trouvent cela difficile.","Et les régimes restrictifs ?"],"female_lines":["Manger varié, cinq fruits et légumes par jour, et limiter les sucres.","Il suffit de petits changements quotidiens, comme remplacer les boissons sucrées par de l'eau.","À éviter, ils ne fonctionnent pas sur le long terme."]}]},{"id":27,"section":"F","theme":"Discussion - Opinions","question":"Quelle est l'opinion principale exprimée ?","options":[{"id":"A","text":"Le télétravail est inefficace","image_prompt":""},{"id":"B","text":"Le télétravail devrait être permanent","image_prompt":""},{"id":"C","text":"Le télétravail a des avantages et des inconvénients","image_prompt":""},{"id":"D","text":"Le télétravail nuit à la santé","image_prompt":""}],"correct":2,"transcript_fr":"Isabelle: Je trouve que le télétravail c'est pratique mais un peu isolant. Robert: C'est vrai, on gagne du temps sur les transports mais on manque de contact humain. Isabelle: Exactement, et puis chez soi il y a plus de distractions. Robert: Mais on est plus concentré pour certaines tâches. Isabelle: C'est pour ça que je préfère un mixte, trois jours au bureau, deux à la maison.","transcript_en":"Isabelle: I find that working from home is practical but a bit isolating. Robert: That's true, we save time on commuting but we lack human contact. Isabelle: Exactly, and at home there are more distractions. Robert: But we are more concentrated for certain tasks. Isabelle: That's why I prefer a mix, three days in the office, two at home.","points":[{"point":1,"male_lines":["C'est vrai, on gagne du temps sur les transports mais on manque de contact humain.","Mais on est plus concentré pour certaines tâches."],"female_lines":["Je trouve que le télétravail c'est pratique mais un peu isolant.","Exactement, et puis chez soi il y a plus de distractions.","C'est pour ça que je préfère un mixte, trois jours au bureau, deux à la maison."]}]},{"id":28,"section":"F","theme":"Discussion - Opinions","question":"Sur quoi les locuteurs ne sont-ils pas d'accord ?","options":[{"id":"A","text":"La qualité de l'enseignement","image_prompt":""},{"id":"B","text":"L'utilité des devoirs","image_prompt":""},{"id":"C","text":"Le nombre d'élèves par classe","image_prompt":""},{"id":"D","text":"Le système de notation","image_prompt":""}],"correct":1,"transcript_fr":"François: Je pense que les devoirs à la maison sont essentiels pour réviser. Nathalie: Pas d'accord, les enfants passent déjà assez de temps à l'école. François: Mais sans pratique à la maison, ils oublient vite. Nathalie: Ils ont besoin de temps libre pour jouer et se reposer. François: Un peu des deux serait idéal. Nathalie: Peut-être, mais pas des heures de travail chaque soir.","transcript_en":"François: I think homework is essential for reviewing. Nathalie: I disagree, children already spend enough time at school. François: But without practice at home, they forget quickly. Nathalie: They need free time to play and rest. François: A bit of both would be ideal. Nathalie: Maybe, but not hours of work every evening.","points":[{"point":1,"male_lines":["Je pense que les devoirs à la maison sont essentiels pour réviser.","Mais sans pratique à la maison, ils oublient vite.","Un peu des deux serait idéal."],"female_lines":["Pas d'accord, les enfants passent déjà assez de temps à l'école.","Ils ont besoin de temps libre pour jouer et se reposer.","Peut-être, mais pas des heures de travail chaque soir."]}]},{"id":29,"section":"F","theme":"Discussion - Opinions","question":"Quel sujet débattent les locuteurs ?","options":[{"id":"A","text":"L'interdiction des voitures en ville","image_prompt":""},{"id":"B","text":"La hausse du prix de l'essence","image_prompt":""},{"id":"C","text":"Les transports en commun gratuits","image_prompt":""},{"id":"D","text":"La construction de nouvelles routes","image_prompt":""}],"correct":0,"transcript_fr":"Philippe: Il faudrait interdire les voitures dans le centre-ville. Claire: C'est impossible, comment feraient les commerçants pour recevoir leurs marchandises ? Philippe: Avec des véhicules électriques de livraison. Claire: Et les personnes âgées qui ne peuvent pas marcher ? Philippe: Des navettes électriques gratuites pourraient les transporter. Claire: Ce serait cher à mettre en place.","transcript_en":"Philippe: We should ban cars from the city center. Claire: That's impossible, how would merchants receive their goods? Philippe: With electric delivery vehicles. Claire: And elderly people who can't walk? Philippe: Free electric shuttles could transport them. Claire: That would be expensive to set up.","points":[{"point":1,"male_lines":["Il faudrait interdire les voitures dans le centre-ville.","Avec des véhicules électriques de livraison.","Des navettes électriques gratuites pourraient les transporter."],"female_lines":["C'est impossible, comment feraient les commerçants pour recevoir leurs marchandises ?","Et les personnes âgées qui ne peuvent pas marcher ?","Ce serait cher à mettre en place."]}]},{"id":30,"section":"F","theme":"Discussion - Opinions","question":"Quelle est la conclusion de la discussion ?","options":[{"id":"A","text":"Ils décident d'aller au cinéma","image_prompt":""},{"id":"B","text":"Ils choisissent de rester chez eux","image_prompt":""},{"id":"C","text":"Ils hésitent encore sur leur choix","image_prompt":""},{"id":"D","text":"Ils vont inviter des amis","image_prompt":""}],"correct":0,"transcript_fr":"Émilie: On fait quoi ce soir ? On sort ou on reste ? David: Je ne sais pas, il fait froid dehors. Émilie: Oui mais il y a ce nouveau film qui a l'air bien. David: Lequel ? Celui avec l'acteur français ? Émilie: Exactement ! Et il passe à 20h au cinéma du coin. David: D'accord, allons-y ! On se retrouve devant à 19h45 ? Émilie: Parfait, à tout à l'heure !","transcript_en":"Émilie: What are we doing tonight? Going out or staying in? David: I don't know, it's cold outside. Émilie: Yes but there's this new movie that looks good. David: Which one? The one with the French actor? Émilie: Exactly! And it's playing at 8pm at the local cinema. David: Okay, let's go! Meet in front at 7:45pm? Émilie: Perfect, see you later!","points":[{"point":1,"male_lines":["Je ne sais pas, il fait froid dehors.","Lequel ? Celui avec l'acteur français ?","D'accord, allons-y ! On se retrouve devant à 19h45 ?"],"female_lines":["On fait quoi ce soir ? On sort ou on reste ?","Oui mais il y a ce nouveau film qui a l'air bien.","Exactement ! Et il passe à 20h au cinéma du coin.","Parfait, à tout à l'heure !"]}]},{"id":31,"section":"G","theme":"Longer text/Argument","question":"Quelle est la thèse principale de cet enregistrement ?","options":[{"id":"A","text":"L'éducation doit être entièrement numérique","image_prompt":""},{"id":"B","text":"Les livres papier restent indispensables","image_prompt":""},{"id":"C","text":"Il faut interdire les écrans à l'école","image_prompt":""},{"id":"D","text":"Le coût de l'éducation est trop élevé","image_prompt":""}],"correct":1,"transcript_fr":"Intervenant 1: Bonjour à tous, aujourd'hui nous débattons de l'avenir du livre dans l'éducation. Madame Bernard, vous êtes directrice d'école. Intervenante 2: Bonjour. Je pense que malgré la technologie, le livre papier garde une place essentielle. Intervenant 1: Pourquoi selon vous ? Intervenante 2: Parce que toucher du doigt, tourner les pages, cela aide la mémorisation. Intervenant 1: Et le côté pratique des tablettes ? Intervenante 2: Certes, mais les écrans fatiguent les yeux des enfants. Intervenant 1: Qu'en est-il du coût ? Intervenante 2: Un livre dure des années, une tablette devient obsolète vite. Intervenant 1: Donc vous défendez le papier ? Intervenante 2: Oui, pour l'équilibre. Numérique oui, mais pas seulement. Intervenant 1: Merci pour ces précisions.","transcript_en":"Speaker 1: Hello everyone, today we are debating the future of books in education. Mrs. Bernard, you are a school principal. Speaker 2: Hello. I think that despite technology, the paper book retains an essential place. Speaker 1: Why do you think so? Speaker 2: Because touching with your finger, turning pages, this helps memorization. Speaker 1: And the practical side of tablets? Speaker 2: Certainly, but screens tire children's eyes. Speaker 1: What about the cost? Speaker 2: A book lasts for years, a tablet becomes obsolete quickly. Speaker 1: So you defend paper? Speaker 2: Yes, for balance. Digital yes, but not only. Speaker 1: Thank you for these details.","points":[{"point":1,"male_lines":["Bonjour à tous, aujourd'hui nous débattons de l'avenir du livre dans l'éducation. Madame Bernard, vous êtes directrice d'école.","Pourquoi selon vous ?","Et le côté pratique des tablettes ?","Qu'en est-il du coût ?","Donc vous défendez le papier ?","Merci pour ces précisions."],"female_lines":["Bonjour. Je pense que malgré la technologie, le livre papier garde une place essentielle.","Parce que toucher du doigt, tourner les pages, cela aide la mémorisation.","Certes, mais les écrans fatiguent les yeux des enfants.","Un livre dure des années, une tablette devient obsolète vite.","Oui, pour l'équilibre. Numérique oui, mais pas seulement."]}]},{"id":32,"section":"G","theme":"Longer text/Argument","question":"Quel argument est présenté contre le projet ?","options":[{"id":"A","text":"Il coûte trop cher","image_prompt":""},{"id":"B","text":"Il détruit l'environnement","image_prompt":""},{"id":"C","text":"Il ne résout pas le problème","image_prompt":""},{"id":"D","text":"Il crée des embouteillages","image_prompt":""}],"correct":1,"transcript_fr":"Intervenant 1: Nous recevons Monsieur Gagnon, opposant au nouveau projet autoroutier. Intervenant 2: Merci de m'accorder la parole. Intervenant 1: Quelles sont vos objections ? Intervenant 2: Cette autoroute traversera des zones humides protégées. Intervenant 1: Le gouvernement dit que ce sera compensé. Intervenant 2: On ne peut pas compenser la destruction d'écosystèmes anciens. Intervenant 1: Mais les embouteillages ? Intervenant 2: Ils reviendront dans cinq ans, c'est prouvé partout. Intervenant 1: Vous proposez quoi alors ? Intervenant 2: Des transports collectifs, des trains, pas des routes. Intervenant 1: Merci de vos arguments.","transcript_en":"Speaker 1: We welcome Mr. Gagnon, opponent of the new highway project. Speaker 2: Thank you for giving me the floor. Speaker 1: What are your objections? Speaker 2: This highway will cross protected wetland areas. Speaker 1: The government says it will be compensated. Speaker 2: You cannot compensate for the destruction of ancient ecosystems. Speaker 1: But the traffic jams? Speaker 2: They will return in five years, it's proven everywhere. Speaker 1: What do you propose then? Speaker 2: Public transportation, trains, not roads. Speaker 1: Thank you for your arguments.","points":[{"point":1,"male_lines":["Nous recevons Monsieur Gagnon, opposant au nouveau projet autoroutier.","Quelles sont vos objections ?","Le gouvernement dit que ce sera compensé.","Mais les embouteillages ?","Vous proposez quoi alors ?","Merci de vos arguments."],"female_lines":["Merci de m'accorder la parole.","Cette autoroute traversera des zones humides protégées.","On ne peut pas compenser la destruction d'écosystèmes anciens.","Ils reviendront dans cinq ans, c'est prouvé partout.","Des transports collectifs, des trains, pas des routes."]}]},{"id":33,"section":"G","theme":"Longer text/Argument","question":"Quelle est la position de l'intervenante sur le sujet ?","options":[{"id":"A","text":"Elle est totalement contre","image_prompt":""},{"id":"B","text":"Elle est favorable avec conditions","image_prompt":""},{"id":"C","text":"Elle n'a pas d'opinion","image_prompt":""},{"id":"D","text":"Elle est indifférente","image_prompt":""}],"correct":1,"transcript_fr":"Intervenant 1: Docteur Petit, vous étudiez les nouvelles technologies médicales. Intervenante 2: Oui, notamment la chirurgie robotique. Intervenant 1: Êtes-vous pour son développement ? Intervenante 2: Oui, mais avec des garde-fous stricts. Intervenant 1: Lesquels ? Intervenante 2: Formation obligatoire des chirurgiens, maintenance rigoureuse. Intervenant 1: Les risques sont donc réels ? Intervenante 2: Comme toute technologie, oui. Mais les bénéfices sont immenses. Intervenant 1: Précision accrue ? Intervenante 2: Exactement, moins de douleur, récupération plus rapide. Intervenant 1: Merci docteur.","transcript_en":"Speaker 1: Dr. Petit, you study new medical technologies. Speaker 2: Yes, particularly robotic surgery. Speaker 1: Are you in favor of its development? Speaker 2: Yes, but with strict safeguards. Speaker 1: Which ones? Speaker 2: Mandatory surgeon training, rigorous maintenance. Speaker 1: So the risks are real? Speaker 2: Like any technology, yes. But the benefits are immense. Speaker 1: Increased precision? Speaker 2: Exactly, less pain, faster recovery. Speaker 1: Thank you doctor.","points":[{"point":1,"male_lines":["Docteur Petit, vous étudiez les nouvelles technologies médicales.","Êtes-vous pour son développement ?","Lesquels ?","Les risques sont donc réels ?","Précision accrue ?","Merci docteur."],"female_lines":["Oui, notamment la chirurgie robotique.","Oui, mais avec des garde-fous stricts.","Formation obligatoire des chirurgiens, maintenance rigoureuse.","Comme toute technologie, oui. Mais les bénéfices sont immenses.","Exactement, moins de douleur, récupération plus rapide."]}]},{"id":34,"section":"G","theme":"Longer text/Argument","question":"Quel est le problème central abordé ?","options":[{"id":"A","text":"Le manque de logements abordables","image_prompt":""},{"id":"B","text":"La gentrification des quartiers","image_prompt":""},{"id":"C","text":"La pollution dans les villes","image_prompt":""},{"id":"D","text":"Le chômage des jeunes","image_prompt":""}],"correct":0,"transcript_fr":"Intervenant 1: Madame Lefebvre, vous travaillez dans l'immobilier social. Intervenante 2: Oui, depuis vingt ans. Intervenant 1: Quel est le plus gros défi actuellement ? Intervenante 2: Le manque criant de logements abordables. Intervenant 1: À Montréal spécifiquement ? Intervenante 2: Partout au Québec. Les loyers explosent, les salaires stagnent. Intervenant 1: Quelles solutions ? Intervenante 2: Plus de construction sociale, encadrement des loyers. Intervenant 1: Le gouvernement écoute-t-il ? Intervenante 2: Pas assez vite, les familles souffrent maintenant. Intervenant 1: Merci de votre témoignage.","transcript_en":"Speaker 1: Mrs. Lefebvre, you work in social housing. Speaker 2: Yes, for twenty years. Speaker 1: What is the biggest challenge currently? Speaker 2: The crying lack of affordable housing. Speaker 1: In Montreal specifically? Speaker 2: Everywhere in Quebec. Rents are exploding, wages are stagnating. Speaker 1: What solutions? Speaker 2: More social construction, rent control. Speaker 1: Is the government listening? Speaker 2: Not fast enough, families are suffering now. Speaker 1: Thank you for your testimony.","points":[{"point":1,"male_lines":["Madame Lefebvre, vous travaillez dans l'immobilier social.","Quel est le plus gros défi actuellement ?","À Montréal spécifiquement ?","Quelles solutions ?","Le gouvernement écoute-t-il ?","Merci de votre témoignage."],"female_lines":["Oui, depuis vingt ans.","Le manque criant de logements abordables.","Partout au Québec. Les loyers explosent, les salaires stagnent.","Plus de construction sociale, encadrement des loyers.","Pas assez vite, les familles souffrent maintenant."]}]},{"id":35,"section":"G","theme":"Longer text/Argument","question":"Quelle conclusion l'intervenant tire-t-il ?","options":[{"id":"A","text":"Il faut augmenter les impôts","image_prompt":""},{"id":"B","text":"L'économie va s'améliorer","image_prompt":""},{"id":"C","text":"Les jeunes doivent partir à l'étranger","image_prompt":""},{"id":"D","text":"Le système actuel est inefficace","image_prompt":""}],"correct":3,"transcript_fr":"Intervenant 1: Monsieur Roy, économiste, analysez-vous la situation actuelle ? Intervenant 2: Avec inquiétude. Nous avons des indicateurs contradictoires. Intervenant 1: Lesquels ? Intervenant 2: Chômage bas mais précarité élevée, croissance mais inflation. Intervenant 1: C'est grave ? Intervenant 2: Cela montre un système qui ne fonctionne plus correctement. Intervenant 1: Votre solution ? Intervenant 2: Réformer en profondeur, pas des patchs temporaires. Intervenant 1: Le gouvernement est-il prêt ? Intervenant 2: Je n'en suis pas sûr, le courage politique manque. Intervenant 1: Merci de cette analyse.","transcript_en":"Speaker 1: Mr. Roy, economist, how do you analyze the current situation? Speaker 2: With concern. We have contradictory indicators. Speaker 1: Which ones? Speaker 2: Low unemployment but high precariousness, growth but inflation. Speaker 1: Is it serious? Speaker 2: This shows a system that no longer works properly. Speaker 1: Your solution? Speaker 2: Deep reform, not temporary patches. Speaker 1: Is the government ready? Speaker 2: I'm not sure, political courage is lacking. Speaker 1: Thank you for this analysis.","points":[{"point":1,"male_lines":["Monsieur Roy, économiste, analysez-vous la situation actuelle ?","Lesquels ?","C'est grave ?","Votre solution ?","Le gouvernement est-il prêt ?","Merci de cette analyse."],"female_lines":["Avec inquiétude. Nous avons des indicateurs contradictoires.","Chômage bas mais précarité élevée, croissance mais inflation.","Cela montre un système qui ne fonctionne plus correctement.","Réformer en profondeur, pas des patchs temporaires.","Je n'en suis pas sûr, le courage politique manque."]}]},{"id":36,"section":"H","theme":"Complex/Abstract recording","question":"Quelle est la métaphore utilisée par l'orateur ?","options":[{"id":"A","text":"La vie est un voyage","image_prompt":""},{"id":"B","text":"Le temps est un fleuve","image_prompt":""},{"id":"C","text":"La société est une machine","image_prompt":""},{"id":"D","text":"L'esprit est un jardin","image_prompt":""}],"correct":1,"transcript_fr":"Conférencier: Mes amis, permettez-moi une réflexion sur le temps qui passe. Auditrice: Nous vous écoutons. Conférencier: Le temps est comme un fleuve impétueux, toujours en mouvement. Auditeur: Une image poétique. Conférencier: Nous ne pouvons pas le retenir, ni remonter le courant. Auditrice: C'est triste et beau à la fois. Conférencier: Exactement. Chaque instant est unique, comme une goutte d'eau. Auditeur: Il faut donc savourer chaque moment ? Conférencier: Précisément. Ne pas regarder en arrière avec regret, mais avancer sereinement. Auditrice: Une leçon de sagesse. Conférencier: Merci de votre attention.","transcript_en":"Speaker: My friends, allow me a reflection on passing time. Female listener: We are listening. Speaker: Time is like a rushing river, always in motion. Male listener: A poetic image. Speaker: We cannot hold it back, nor swim against the current. Female listener: It's sad and beautiful at the same time. Speaker: Exactly. Each moment is unique, like a drop of water. Male listener: So we must savor each moment? Speaker: Precisely. Not to look back with regret, but to move forward serenely. Female listener: A lesson in wisdom. Speaker: Thank you for your attention.","points":[{"point":1,"male_lines":["Mes amis, permettez-moi une réflexion sur le temps qui passe.","Le temps est comme un fleuve impétueux, toujours en mouvement.","Nous ne pouvons pas le retenir, ni remonter le courant.","Exactement. Chaque instant est unique, comme une goutte d'eau.","Précisément. Ne pas regarder en arrière avec regret, mais avancer sereinement.","Merci de votre attention."],"female_lines":["Nous vous écoutons.","Une image poétique.","C'est triste et beau à la fois.","Il faut donc savourer chaque moment ?","Une leçon de sagesse."]}]},{"id":37,"section":"H","theme":"Complex/Abstract recording","question":"Quel concept philosophique est discuté ?","options":[{"id":"A","text":"Le libre arbitre","image_prompt":""},{"id":"B","text":"L'identité personnelle","image_prompt":""},{"id":"C","text":"La justice sociale","image_prompt":""},{"id":"D","text":"Le bonheur","image_prompt":""}],"correct":0,"transcript_fr":"Philosophe: Question fondamentale: sommes-nous vraiment libres de nos choix ? Étudiante: C'est débattu depuis des siècles. Philosophe: Si nos décisions dépendent de notre éducation, de nos gènes ? Étudiant: Alors nous ne serions pas libres ? Philosophe: C'est le déterminisme. Mais l'expérience subjective suggère le contraire. Étudiante: Nous sentons que nous choisissons. Philosophe: Exactement. Le libre arbitre est peut-être une illusion nécessaire. Étudiant: Une illusion qui permet de vivre ? Philosophe: Précisément. Sans sentiment de liberté, pas de responsabilité morale. Étudiante: Fascinant paradoxe.","transcript_en":"Philosopher: Fundamental question: are we truly free in our choices? Female student: This has been debated for centuries. Philosopher: If our decisions depend on our upbringing, our genes? Male student: Then we wouldn't be free? Philosopher: That's determinism. But subjective experience suggests the opposite. Female student: We feel that we choose. Philosopher: Exactly. Free will may be a necessary illusion. Male student: An illusion that allows us to live? Philosopher: Precisely. Without a feeling of freedom, no moral responsibility. Female student: Fascinating paradox.","points":[{"point":1,"male_lines":["Question fondamentale: sommes-nous vraiment libres de nos choix ?","Si nos décisions dépendent de notre éducation, de nos gènes ?","C'est le déterminisme. Mais l'expérience subjective suggère le contraire.","Exactement. Le libre arbitre est peut-être une illusion nécessaire.","Précisément. Sans sentiment de liberté, pas de responsabilité morale."],"female_lines":["C'est débattu depuis des siècles.","Alors nous ne serions pas libres ?","Nous sentons que nous choisissons.","Une illusion qui permet de vivre ?","Fascinant paradoxe."]}]},{"id":38,"section":"H","theme":"Complex/Abstract recording","question":"Quelle est la thèse défendue par l'orateur ?","options":[{"id":"A","text":"L'art doit être accessible à tous","image_prompt":""},{"id":"B","text":"L'art est inutile dans la société","image_prompt":""},{"id":"C","text":"L'art doit provoquer pour exister","image_prompt":""},{"id":"D","text":"L'art est réservé aux élites","image_prompt":""}],"correct":0,"transcript_fr":"Conférencier: L'art n'est pas un luxe, c'est un besoin fondamental. Auditrice: Comment cela ? Conférencier: Comme la nourriture pour le corps, l'art nourrit l'âme. Auditeur: Mais tout le monde n'a pas accès aux musées. Conférencier: C'est le problème ! L'art doit sortir des murs. Auditrice: Dans la rue ? Conférencier: Exactement. Des concerts gratuits, des expositions en plein air. Auditeur: C'est coûteux pour les artistes. Conférencier: L'État doit subventionner. La culture n'est pas une dépense, c'est un investissement. Auditrice: Une vision démocratique. Conférencier: L'art appartient à tous.","transcript_en":"Speaker: Art is not a luxury, it is a fundamental need. Female listener: How so? Speaker: Like food for the body, art nourishes the soul. Male listener: But not everyone has access to museums. Speaker: That's the problem! Art must come out of the walls. Female listener: Into the streets? Speaker: Exactly. Free concerts, outdoor exhibitions. Male listener: It's expensive for artists. Speaker: The State must subsidize. Culture is not an expense, it's an investment. Female listener: A democratic vision. Speaker: Art belongs to everyone.","points":[{"point":1,"male_lines":["L'art n'est pas un luxe, c'est un besoin fondamental.","Comme la nourriture pour le corps, l'art nourrit l'âme.","C'est le problème ! L'art doit sortir des murs.","Exactement. Des concerts gratuits, des expositions en plein air.","L'État doit subventionner. La culture n'est pas une dépense, c'est un investissement.","L'art appartient à tous."],"female_lines":["Comment cela ?","Mais tout le monde n'a pas accès aux musées.","Dans la rue ?","C'est coûteux pour les artistes.","Une vision démocratique."]}]},{"id":39,"section":"H","theme":"Complex/Abstract recording","question":"Quelle est la critique principale formulée ?","options":[{"id":"A","text":"La technologie nous aliène","image_prompt":""},{"id":"B","text":"La technologie progresse trop vite","image_prompt":""},{"id":"C","text":"La technologie crée des inégalités","image_prompt":""},{"id":"D","text":"La technologie détruit l'emploi","image_prompt":""}],"correct":0,"transcript_fr":"Conférencier: Nous sommes devenus esclaves de nos écrans. Auditrice: C'est une vision pessimiste. Conférencier: Regardez autour de vous: tous sur leur téléphone. Auditeur: C'est l'hyperconnexion. Conférencier: Exactement. Nous sommes là mais ailleurs mentalement. Auditrice: Nous communiquons pourtant plus. Conférencier: Quantité ou qualité ? Vraie connexion humaine ? Auditeur: On se sent parfois seul malgré tout. Conférencier: C'est l'aliénation numérique. Nous avons remplacé le regard par le like. Auditrice: Il faut revenir à l'essentiel. Conférencier: Oui, être présent vraiment.","transcript_en":"Speaker: We have become slaves to our screens. Female listener: That's a pessimistic view. Speaker: Look around you: everyone on their phone. Male listener: It's hyperconnectivity. Speaker: Exactly. We are here but elsewhere mentally. Female listener: Yet we communicate more. Speaker: Quantity or quality? Real human connection? Male listener: We sometimes feel lonely despite everything. Speaker: This is digital alienation. We have replaced the gaze with the like. Female listener: We must return to what is essential. Speaker: Yes, to be truly present.","points":[{"point":1,"male_lines":["Nous sommes devenus esclaves de nos écrans.","Regardez autour de vous: tous sur leur téléphone.","Exactement. Nous sommes là mais ailleurs mentalement.","Quantité ou qualité ? Vraie connexion humaine ?","C'est l'aliénation numérique. Nous avons remplacé le regard par le like.","Oui, être présent vraiment."],"female_lines":["C'est une vision pessimiste.","C'est l'hyperconnexion.","Nous communiquons pourtant plus.","On se sent parfois seul malgré tout.","Il faut revenir à l'essentiel."]}]},{"id":40,"section":"H","theme":"Complex/Abstract recording","question":"Quelle est la conclusion de la réflexion ?","options":[{"id":"A","text":"Il faut changer de société","image_prompt":""},{"id":"B","text":"Il faut accepter l'imperfection","image_prompt":""},{"id":"C","text":"Il faut lutter contre l'injustice","image_prompt":""},{"id":"D","text":"Il faut valoriser l'excellence","image_prompt":""}],"correct":1,"transcript_fr":"Conférencier: Nous vivons dans une société de la perfection. Auditrice: Tout doit être optimal. Conférencier: Exactement. Parfait corps, parfait travail, parfaite vie. Auditeur: C'est épuisant. Conférencier: Et impossible. L'erreur est humaine. Auditrice: Mais on nous punit pour nos échecs. Conférencier: C'est le problème. Apprendre de ses erreurs, c'est grandir. Auditeur: Accepter d'être imparfait ? Conférencier: Oui ! La vulnérabilité n'est pas une faiblesse. Auditrice: C'est une force. Conférencier: Soyons humains, pas des machines.","transcript_en":"Speaker: We live in a society of perfection. Female listener: Everything must be optimal. Speaker: Exactly. Perfect body, perfect job, perfect life. Male listener: It's exhausting. Speaker: And impossible. To err is human. Female listener: But we are punished for our failures. Speaker: That's the problem. Learning from mistakes is growing. Male listener: Accept being imperfect? Speaker: Yes! Vulnerability is not weakness. Female listener: It's strength. Speaker: Let's be human, not machines.","points":[{"point":1,"male_lines":["Nous vivons dans une société de la perfection.","Exactement. Parfait corps, parfait travail, parfaite vie.","Et impossible. L'erreur est humaine.","C'est le problème. Apprendre de ses erreurs, c'est grandir.","Oui ! La vulnérabilité n'est pas une faiblesse.","Soyons humains, pas des machines."],"female_lines":["Tout doit être optimal.","C'est épuisant.","Mais on nous punit pour nos échecs.","Accepter d'être imparfait ?","C'est une force."]}]}]`);export{e as default};
